import{_ as e,c as i,o as l,a}from"./app.87b1f767.js";const m=JSON.parse('{"title":"标识符","description":"","frontmatter":{},"headers":[{"level":2,"title":"组成规则","slug":"组成规则","link":"#组成规则","children":[]},{"level":2,"title":"注意事项","slug":"注意事项","link":"#注意事项","children":[]},{"level":2,"title":"标识符的规范","slug":"标识符的规范","link":"#标识符的规范","children":[]}],"relativePath":"java/basis/index4.md"}'),t={name:"java/basis/index4.md"},r=a('<h1 id="标识符" tabindex="-1">标识符 <a class="header-anchor" href="#标识符" aria-hidden="true">#</a></h1><p>就是给类，接口，变量等起名字时使用的字符序列</p><h2 id="组成规则" tabindex="-1">组成规则 <a class="header-anchor" href="#组成规则" aria-hidden="true">#</a></h2><ul><li>英文大小写字母</li><li>数字字符</li><li>$ 和 _</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-hidden="true">#</a></h2><ul><li>不能以数字开头</li><li>不能是 java 中的关键字</li><li>区别大小写</li></ul><h2 id="标识符的规范" tabindex="-1">标识符的规范 <a class="header-anchor" href="#标识符的规范" aria-hidden="true">#</a></h2><p>1、包名</p><ul><li>其实就是文件夹，解决相同类名的问题</li><li>包名要求全部小写，一般是公司的域名倒着写</li><li><a href="http://www.baidu.com" target="_blank" rel="noreferrer">www.baidu.com</a> --&gt; com.baidu</li></ul><p>2、类名</p><ul><li>首字母大写，多个单词相连的时候，每个单词的首字母都要大写(驼峰命名)，因为多个单词连接，可能会组成新的单词，可能会造成歧义</li><li>Demo</li><li>TeseDemo</li></ul><p>3、方法和变量</p><ul><li>一个单词时，首字母小写，多个单词时，从第二个单词开始，所有的单词的首字母都要大写</li><li>get</li><li>getName</li></ul><p>4、常量</p><ul><li>所有字母大写，多个单词连接时，使用下划线（_）连接，主要是字母全部大写之后如果没有分割符，就很难区分单词，造成理解混乱</li><li>MAX</li><li>MAX_VALUE</li></ul>',15),d=[r];function n(s,h,c,o,_,u){return l(),i("div",null,d)}const f=e(t,[["render",n]]);export{m as __pageData,f as default};
